const raw = $input.first().json;
const q = raw.query || raw.params || {};
const order_number = Array.isArray(q.order_number) ? q.order_number[0] : (q.order_number || '');
const order_number_esc = String(order_number).replace(/'/g, "''");
const query = `SELECT uo.id, uo.order_number, uo.user_id, uo.payment_status AS status, uo.payment_status, uo.payment_intent_id, uo.total_amount, uo.paid_at, uo.created_at, u.name AS user_name, (SELECT procedure_name FROM paid_orders WHERE order_id = uo.id LIMIT 1) AS procedure_name, (SELECT room_number FROM paid_orders WHERE order_id = uo.id LIMIT 1) AS room_number FROM unpaid_orders uo LEFT JOIN users u ON uo.user_id = u.id WHERE uo.order_number = '${order_number_esc}'`;
return [{ json: { query } }];
